import React, { useState } from "react";
import axios from "axios";

function App() {
  const [matricula, setMatricula] = useState("");
  const [senha, setSenha] = useState("");
  const [loggedIn, setLoggedIn] = useState(false);
  const [formData, setFormData] = useState({
    data_atividade: "",
    supervisor: "",
    status: "",
    eletricista_motorista: "",
    eletricista_parceiro: "",
    equipe: "",
    servico: "",
    placa_veiculo: "",
  });
  const [teams, setTeams] = useState([]);

  const handleLogin = async () => {
    try {
      const response = await axios.post("http://localhost:5000/login", { matricula, senha });
      if (response.data.message === "Login bem-sucedido") {
        setLoggedIn(true);
        alert("Login bem-sucedido!");
      }
    } catch (error) {
      alert("Erro ao fazer login");
    }
  };

  const fetchTeams = async () => {
    try {
      const response = await axios.get("http://localhost:5000/teams", {
        params: {
          data: formData.data_atividade,
        },
      });
      setTeams(response.data);
    } catch (error) {
      console.error("Erro ao buscar equipes:", error);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/teams", formData);
      setFormData({
        data_atividade: "",
        supervisor: "",
        status: "",
        eletricista_motorista: "",
        eletricista_parceiro: "",
        equipe: "",
        servico: "",
        placa_veiculo: "",
      });
      fetchTeams(); // Atualiza a lista de equipes
    } catch (error) {
      alert("Erro ao cadastrar equipe");
    }
  };

  if (!loggedIn) {
    return (
      <div>
        <h1>Login</h1>
        <input
          type="text"
          placeholder="Matrícula"
          value={matricula}
          onChange={(e) => setMatricula(e.target.value)}
        />
        <input
          type="password"
          placeholder="Senha"
          value={senha}
          onChange={(e) => setSenha(e.target.value)}
        />
        <button onClick={handleLogin}>Entrar</button>
      </div>
    );
  }

  return (
    <div>
      <h1>Cadastro de Equipes</h1>
      <form onSubmit={handleSubmit}>
        <input
          type="date"
          name="data_atividade"
          value={formData.data_atividade}
          onChange={handleChange}
          required
        />
        <input
          type="text"
          name="supervisor"
          value={formData.supervisor}
          onChange={handleChange}
          placeholder="Supervisor"
          required
        />
        <input
          type="text"
          name="status"
          value={formData.status}
          onChange={handleChange}
          placeholder="Status"
          required
        />
        <input
          type="text"
          name="eletricista_motorista"
          value={formData.eletricista_motorista}
          onChange={handleChange}
          placeholder="Eletricista Motorista"
          required
        />
        <input
          type="text"
          name="eletricista_parceiro"
          value={formData.eletricista_parceiro}
          onChange={handleChange}
          placeholder="Eletricista Parceiro"
          required
        />
        <input
          type="text"
          name="equipe"
          value={formData.equipe}
          onChange={handleChange}
          placeholder="Equipe"
          required
        />
        <input
          type="text"
          name="servico"
          value={formData.servico}
          onChange={handleChange}
          placeholder="Serviço"
          required
        />
        <input
          type="text"
          name="placa_veiculo"
          value={formData.placa_veiculo}
          onChange={handleChange}
          placeholder="Placa do Veículo"
          required
        />
        <button type="submit">Cadastrar</button>
      </form>

      <button onClick={fetchTeams}>Buscar Equipes</button>

      <h2>Equipes Cadastradas</h2>
      <table>
        <thead>
          <tr>
            <th>Data</th>
            <th>Supervisor</th>
            <th>Status</th>
            <th>Equipe</th>
            <th>Eletricista Motorista</th>
            <th>Eletricista Parceiro</th>
            <th>Serviço</th>
            <th>Placa</th>
          </tr>
        </thead>
        <tbody>
          {teams.map((team) => (
            <tr key={team.id}>
              <td>{team.data_atividade}</td>
              <td>{team.supervisor}</td>
              <td>{team.status}</td>
              <td>{team.equipe}</td>
              <td>{team.eletricista_motorista}</td>
              <td>{team.eletricista_parceiro}</td>
              <td>{team.servico}</td>
              <td>{team.placa_veiculo}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;
